INSERT INTO `meta_sorgente` (`ID_SORGENTE`, `REPORT_NAME`, `REPORT_DESC`)
VALUES
    ('comuni', 'Elenco dei codici e delle denominazioni delle unità territoriali', 'Il report restituisce l''elenco dei comuni attivi alla data selezionata. L''orizzonte temporale entro cui è possibile impostare la data di analisi si estende dal 01/01/1948 – data di entrata in vigore della Costituzione della Repubblica Italiana – sino alla data odierna. I dati estratti riflettono unicamente il quadro territoriale del giorno prescelto. Per ciascun comune, identificato dalla denominazione ufficiale e dal codice statistico, sono indicati i legami di appartenenza ai livelli territoriali sovraordinati (ripartizioni geografiche, regioni e province/UTS). La disponibilità di alcune variabili è subordinata alla data selezionata: i codici NUTS di riferimento sono presenti a partire dal 2006, mentre il codice fiscale dell''ente è inserito per le selezioni a partire dal 1991. Sono altresì fornite le caratteristiche amministrative dell''epoca quali lo stato di capoluogo, la sigla automobilistica e il codice catastale.'),
    ('comuni_caratteristiche', 'Comuni - Caratteristiche del territorio', 'L’Istat, ai fini di una descrizione statistica delle caratteristiche geografiche del territorio, diffonde elaborazioni basate sui dati collezionati in occasione delle rilevazioni censuarie o provenienti da altre fonti con riferimento alle principali unità territoriali di interesse per la statistica ufficiale. In questo quadro, il report restituisce la lista dei comuni esistenti alla data selezionata e le relative caratteristiche territoriali. L''orizzonte temporale dell''analisi si estende dal 01/01/1948 sino alla data odierna, mostrando unicamente il quadro territoriale del giorno prescelto. Ciascun comune è identificato dalla denominazione ufficiale e dal codice statistico. La disponibilità delle variabili è subordinata alla data selezionata: litoraneità e zona altimetrica sono consultabili dal 1948, le zone costiere dal 2008, il grado di urbanizzazione dal 09/10/2011 (XV Censimento), le ecoregioni dal 2018 e l''altimetria dal 31/12/2021'),
    ('comuni_dimensione', 'Comuni - Dimensione', 'Il report restituisce la lista dei comuni esistenti alla data selezionata, corredata dalla relativa dimensione in termini di ampiezza demografica (popolazione residente e legale) e di estensione territoriale (superficie in kmq). L''orizzonte temporale entro cui è possibile impostare la data di analisi si estende dal 04/11/1951 (IX Censimento generale della popolazione) sino alla data odierna. I dati estratti riflettono unicamente il quadro territoriale del giorno prescelto. Ciascun comune è identificato dalla denominazione ufficiale e dal codice statistico. La popolazione legale è presente per l''intero arco temporale del report, la superficie territoriale è inserita per le selezioni a partire dal 21/10/2001 (XIV Censimento generale), mentre la popolazione residente è disponibile a partire dal 31/12/2001.'),
    ('province_uts', 'Elenco Province/Uts', 'Il report restituisce l''elenco delle province o unità territoriali sovracomunali (UTS) attive alla data selezionata. L''orizzonte temporale entro cui è possibile impostare la data di analisi si estende dal 01/01/1948 – data di entrata in vigore della Costituzione della Repubblica Italiana – sino alla data odierna. I dati estratti riflettono unicamente il quadro territoriale del giorno prescelto. Per ciascuna unità, identificata dalla denominazione ufficiale, dal codice statistico e dalla tipologia di ente, sono resi disponibili i legami di appartenenza ai livelli territoriali sovraordinati (ripartizioni geografiche e regioni) e i codici NUTS (consultabili a partire dal 2006). Sono inoltre fornite le principali caratteristiche amministrative disponibili, quali la sigla automobilistica e il codice fiscale dell''ente (disponibile dal 1991).'),
    ('regioni', 'Elenco Regioni', 'Il report restituisce l''elenco delle regioni attive alla data selezionata. L''orizzonte temporale entro cui è possibile impostare la data di analisi si estende dal 01/01/1948 – data di entrata in vigore della Costituzione della Repubblica Italiana che ha istituzionalizzato l''assetto regionale dello Stato – sino alla data odierna. I dati estratti riflettono unicamente il quadro territoriale del giorno prescelto. Per ciascuna regione, identificata dalla denominazione ufficiale e dal codice statistico, sono indicati la tipologia di statuto dell''ente e i legami con i codici NUTS di riferimento (presenti a partire dal 2006). Il codice fiscale dell''ente è inserito per le selezioni a partire dal 1991.'),
    ('ripartizioni', 'Elenco Ripartizioni geografiche', 'Il report restituisce l''elenco delle ripartizioni geografiche alla data selezionata, secondo la suddivisione in cinque aree dello standard Eurostat (livello NUTS 1). L''orizzonte temporale entro cui è possibile impostare la data di analisi si estende dal 01/01/1948 – data di entrata in vigore della Costituzione della Repubblica Italiana – sino alla data odierna. I dati estratti riflettono unicamente il quadro territoriale del giorno prescelto. Ciascuna ripartizione è identificata dalla denominazione ufficiale, dal codice statistico e dal relativo codice NUTS (quest''ultimo disponibile per le selezioni a partire dal 2006).')
INSERT INTO `meta_colonna` (`ID_SORGENTE`, `COLNAME`, `LABEL`, `TYPE`, `GUIDA`, `NOTE`, `FONTE`, `LINK`, `FORMATMASK`)
VALUES
    ('comuni', 'CC_REG', 'Capoluogo di regione', 'NUMBER', '1=Comune capoluogo; 0= Comune non capoluogo', 'Note non presenti', 'Istat', '', ''),
    ('comuni', 'CC_UTS', 'Capoluogo di provincia/uts', 'NUMBER', '1=Comune capoluogo; 0= Comune non capoluogo', 'Comune capoluogo della Provincia, e dal 2015 della Città metropolitana o Libero consorzio, in cui hanno sede i relativi organi amministrativi locali. Ai sensi dell''art. 46 della legge regionale 20/2016 del Friuli-Venezia Giulia, i Comuni di Trieste, Udine, Pordenone e Gorizia mantengono le prerogative connesse alla qualificazione di “Capoluogo di Provincia”.', 'Istat', '', ''),
    ('comuni', 'COD_CATASTO', 'Codice catasto', 'VARCHAR', 'Codice assegnato dall''Agenzia delle Entrate per finalità amministrative e utilizzato, tra l''altro, anche nella composizione del Codice Fiscale. N.d.=quando non disponibile', 'Elaborazione Istat su dati dell''Agenzia delle Entrate.', 'Agenzia delle Entrate', 'https://www.agenziaentrate.gov.it/portale/schede/fabbricatiterreni/archivio-comuni-e-stati-esteri/consultazione-archivio-comuni-stati-esteri', ''),
    ('comuni', 'COD_COM_FISCALE', 'Codice fiscale', 'VARCHAR', 'Identificativo di 11 cifre assegnato dall''Anagrafe Tributaria che identifica univocamente l''ente pubblico locale. Null quando non disponibile.', 'Dati disponibili dal 1/1/1991', 'Agenzia delle Entrate', '', ''),
    ('comuni', 'COD_PROV_STORICO', 'Codice Provincia (Storico)', 'VARCHAR', 'Codice Istat della Provincia vigente o cessata (tre caratteri, formato alfanumerico con validità nell’intervallo 001-119)', 'A partire dal 1/1/2015 con l''entrata in vigore delle città metropolitane i codici delle province corrispondenti permangono al solo scopo di costituire il codice del comune, che non subisce variazioni. Allo stesso scopo, e ai soli fini statistici, permangono i codici delle soppresse province del Friuli-Venezia Giulia (l.r. 20/2016)', 'Istat', '', ''),
    ('comuni', 'COD_REG', 'Codice Regione', 'VARCHAR', 'Codice Istat di due caratteri alfanumerici, con validità nell''intervallo  01- 20.', 'Valore  di due caratteri alfanumerici, con validità nell''intervallo  01- 20.', 'Istat', '', ''),
    ('comuni', 'COD_RIP', 'Codice Ripartizione geografica', 'NUMBER', 'Codice Istat in formato numerico secondo la suddivisione del territorio nazionale in: 1) Nord-ovest, 2) Nord-est, 3) Centro, 4) Sud e 5) Isole.', 'Note non presenti', 'Istat', '', ''),
    ('comuni', 'COD_UTS', 'Codice Provincia/Uts', 'VARCHAR', 'Codice Istat della Provincia o Unità territoriale sovracomunale (Uts). Le unità territoriali sovracomunali, definite a fini statistici, ricomprendono, a partire dal 2015, oltre le Province anche le Città metropolitane, i Liberi consorzi e le unità non amministrative (ex Province del Friuli-Venezia Giulia).', 'Codice di tre caratteri alfanumerici con validità nell’intervallo 001-119 per le province. Restano assegnati ai liberi consorzi i codici delle omonime ex Province (validi nell''intervallo 081-089). Il codice delle Città metropolitane è, invece, creato sommando ''200'' al codice della provincia corrispondente. Ai soli fini statistici, permangono i codici delle soppresse Province del Friuli-Venezia Giulia, cessate secondo le modalità espresse con Legge regionale 20/2016.', 'Istat', '', ''),
    ('comuni', 'COMUNE', 'Comune', 'VARCHAR', 'Denominazione in lingua italiana e straniera e del Comune', 'La denominazione ufficiale dei comuni della Provincia di Bolzano/Bozen e di alcuni Comuni dell Friuli-Venezia Giulia è definita dall''associazione del nome italiano a quello straniero. Per le denominazioni bilingue è previsto l''uso del simbolo separatore: "/" per i comuni della Provincia di Bolzano/Bozen, e "-" per tutti gli altri.', 'Istat', '', ''),
    ('comuni', 'COMUNE_A', 'Comune (dizione straniera)', 'VARCHAR', 'Denominazione in lingua straniera', 'Note non presenti', 'Istat', '', ''),
    ('comuni', 'COMUNE_IT', 'Comune (dizione italiana)', 'VARCHAR', 'Denominazione in lingua italiana', 'Note non presenti', 'Istat', '', ''),
    ('comuni', 'COM_NUTS1_2024', 'Codice NUTS1 2024', 'VARCHAR', 'Nomenclatura delle unità territoriali europee (NUTS1) corrispondente al livello territoriale di Ripartizione geografica, valida dal 2024', 'Cfr. Commission Delegated Regulation 674/2023', 'Eurostat', 'https://ec.europa.eu/eurostat/web/nuts/history', ''),
    ('comuni', 'COM_NUTS2_2024', 'Codice NUTS2 2024', 'VARCHAR', 'Nomenclatura delle unità territoriali europee (NUTS2) corrispondente al livello territoriale delle Regioni, valida dal 2024', 'Cfr. Commission Delegated Regulation 674/2023. Nella nomenclatura NUTS non è presente la regione di livello 2 "Trentino-Alto Adige/Südtirol"; al suo posto compaiono la "Provincia autonoma di Bolzano/Bozen" (ITH1) e la "Provincia autonoma di Trento" (ITH2).', 'Eurostat', 'https://ec.europa.eu/eurostat/web/nuts/history', ''),
    ('comuni', 'COM_NUTS3_2024', 'Codice NUTS3 2024', 'VARCHAR', 'Nomenclatura delle unità territoriali europee (NUTS3) corrispondente al livello territoriale delle Province/Citta metropolitane (Uts-Unità territoriali sovracomunali), valida dal 2024 con il cambio denominazione della Nuts3 Reggio di Calabria in Reggio Calabria, fino al 2026.', 'Cfr. Commission Delegated Regulation 2023/674', 'Eurostat', 'https://ec.europa.eu/eurostat/web/nuts/history', ''),
    ('comuni', 'DEN_REG', 'Regione', 'VARCHAR', 'Denominazione della Regione', 'Note non presenti', 'Istat', '', ''),
    ('comuni', 'DEN_RIP', 'Ripartizione geografica', 'VARCHAR', 'Denominazione della Ripartizione geografica', 'Note non presenti', '', '', ''),
    ('comuni', 'DEN_UTS', 'Provincia/Uts', 'VARCHAR', 'Denominazione della provincia o unità territoriale sovracomunale (uts)', 'Note non presenti', 'Istat', '', ''),
    ('comuni', 'PRO_COM', 'Codice Comune (numerico)', 'NUMBER', 'Codice Istat di sei caratteri in formato numerico', 'Note non presenti', 'Istat', '', ''),
    ('comuni', 'PRO_COM_T', 'Codice Comune (alfanumerico)', 'VARCHAR', 'Codice Istat di sei caratteri in formato alfanumerico.', 'Note non presenti', 'Istat', '', ''),
    ('comuni', 'SIGLA_AUTOMOBILISTICA', 'Sigla automobilistica', 'VARCHAR', 'Codice identificativo di due lettere associato alla provincia e, dal 2015, alla città metropolitana, al libero consorzio o all''unità non amministrativa (ex province del Friuli-Venezia Giulia). Il valore è Null quando il dato non è disponibile', 'Riferimenti normativi: Cfr. D.P.R. 16 dicembre 1992, n. 495 (Allegato XI, comma 1-bis) e successive modificazioni e integrazioni; D.P.R. 12 settembre 2017 (pubblicato in G.U. n. 222/2017 per l''adozione della sigla SU- Provincia del Sud Sardegna).
